@rendermode InteractiveServer
@using sv_27d95f46d2cd48e387ed57138e0792db.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => SetActiveSection(section.Key)">
                        <span class="section-icon">@section.Value.Icon</span>
                        @section.Value.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfile()
                    break;
                case "notifications":
                    @RenderNotifications()
                    break;
                case "security":
                    @RenderSecurity()
                    break;
                case "appearance":
                    @RenderAppearance()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="toast-notification @(_toastFading ? "fade-out" : "")">
                <span class="toast-icon">✓</span> @_toastMessage
            </div>
        }

        @if (_showRevokeDialog)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong>?</p>
                            <p class="text-muted small">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke Session</button>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // Toast
    private string? _toastMessage;
    private bool _toastFading;
    private CancellationTokenSource? _toastCts;

    // Profile state
    private string _profileName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // Notification state
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelItem> _channels = new();

    // Security state
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;

    // Appearance state
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _availableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Portuguese", "Chinese"];

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨"),
    };

    private record ChannelItem(string Name, bool Muted);

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData();
    }

    private async Task SetActiveSection(string section)
    {
        ActiveSection = section;
        _loading = true;
        await LoadSectionData();
    }

    private async Task LoadSectionData()
    {
        switch (ActiveSection)
        {
            case "profile":
                var profile = await SettingsService.GetProfileAsync();
                _savedProfile = profile;
                _profileName = profile.DisplayName;
                _profileEmail = profile.Email;
                _profileAvatarUrl = profile.AvatarUrl;
                _profileBio = profile.Bio;
                break;

            case "notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _emailNotifications = prefs.EmailNotifications;
                _pushNotifications = prefs.PushNotifications;
                _weeklyDigest = prefs.WeeklyDigest;
                _channels = prefs.MutedChannels
                    .Select(c => new ChannelItem(c, true))
                    .ToList();
                break;

            case "security":
                _security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = _security.TwoFactorEnabled;
                _changePasswordExpanded = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                _passwordError = null;
                break;

            case "appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _theme = appearance.Theme;
                _fontSize = appearance.FontSize;
                _language = appearance.Language;
                _compactMode = appearance.CompactMode;
                break;
        }
        _loading = false;
    }

    // --- Toast ---
    private async Task ShowToast(string message)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastFading = false;
        StateHasChanged();

        try
        {
            await Task.Delay(2500, token);
            _toastFading = true;
            StateHasChanged();
            await Task.Delay(500, token);
            _toastMessage = null;
            _toastFading = false;
        }
        catch (TaskCanceledException) { }
    }

    // --- Profile ---
    private async Task SaveProfile()
    {
        var updated = new UserProfile(_profileName, _profileEmail, _profileAvatarUrl, _profileBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            _profileName = _savedProfile.DisplayName;
            _profileEmail = _savedProfile.Email;
            _profileAvatarUrl = _savedProfile.AvatarUrl;
            _profileBio = _savedProfile.Bio;
        }
    }

    // --- Notifications ---
    private void ToggleChannel(int index)
    {
        var ch = _channels[index];
        _channels[index] = ch with { Muted = !ch.Muted };
    }

    private async Task SaveNotifications()
    {
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    // --- Security ---
    private async Task UpdatePassword()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        await ShowToast("Password updated successfully!");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
        }
        _showRevokeDialog = false;
        _sessionToRevoke = null;
        await ShowToast("Session revoked.");
    }

    // --- Appearance ---
    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e2e",
        _ => "#ffffff"
    };

    private string PreviewColor => _theme switch
    {
        "Dark" => "#cdd6f4",
        _ => "#212529"
    };

    // --- Render fragments ---

    private RenderFragment RenderProfile() => __builder =>
    {
        <h3 class="settings-section-title">Profile</h3>

        <div class="card settings-card">
            <div class="card-body">
                <div class="row">
                    <div class="col-md-8">
                        <div class="mb-3">
                            <label class="form-label fw-semibold">Display Name</label>
                            <input type="text" class="form-control" @bind="_profileName" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label fw-semibold">Email</label>
                            <input type="email" class="form-control" @bind="_profileEmail" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label fw-semibold">Bio</label>
                            <textarea class="form-control" rows="4" @bind="_profileBio"></textarea>
                        </div>
                    </div>
                    <div class="col-md-4 text-center">
                        <label class="form-label fw-semibold d-block">Avatar Preview</label>
                        <div class="avatar-preview">
                            <img src="@_profileAvatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
                        </div>
                        <div class="mt-2">
                            <small class="text-muted text-break">@_profileAvatarUrl</small>
                        </div>
                    </div>
                </div>
                <hr />
                <div class="d-flex gap-2">
                    <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                    <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
                </div>
            </div>
        </div>
    };

    private RenderFragment RenderNotifications() => __builder =>
    {
        <h3 class="settings-section-title">Notifications</h3>

        <div class="card settings-card">
            <div class="card-body">
                <div class="mb-3">
                    <div class="form-check form-switch mb-2">
                        <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                        <label class="form-check-label" for="emailNotif">Email Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-2">
                        <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                        <label class="form-check-label" for="pushNotif">Push Notifications</label>
                    </div>
                    <div class="form-check form-switch mb-2">
                        <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                        <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                    </div>
                </div>

                <hr />
                <h6 class="fw-semibold">Channels</h6>
                <p class="text-muted small">Check channels you want to mute.</p>
                <div class="row">
                    @for (int i = 0; i < _channels.Count; i++)
                    {
                        var index = i;
                        var ch = _channels[index];
                        <div class="col-md-6 col-lg-4 mb-2">
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" checked="@ch.Muted"
                                       id="ch-@index" @onchange="() => ToggleChannel(index)" />
                                <label class="form-check-label" for="ch-@index">#@ch.Name</label>
                            </div>
                        </div>
                    }
                </div>

                <hr />
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </div>
    };

    private RenderFragment RenderSecurity() => __builder =>
    {
        <h3 class="settings-section-title">Security</h3>

        <!-- Change Password -->
        <div class="card settings-card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor:pointer" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span>@(_changePasswordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_changePasswordExpanded)
            {
                <div class="card-body">
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="UpdatePassword">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="card settings-card mb-3">
            <div class="card-body">
                <div class="d-flex align-items-center justify-content-between">
                    <div>
                        <h6 class="mb-1 fw-semibold">Two-Factor Authentication</h6>
                        <small class="text-muted">
                            @if (_twoFactorEnabled)
                            {
                                <span class="badge bg-success me-1">Enabled</span>
                                @:Your account has an extra layer of security.
                            }
                            else
                            {
                                <span class="badge bg-warning text-dark me-1">Disabled</span>
                                @:Add an extra layer of security to your account.
                            }
                        </small>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
                @if (_security?.LastPasswordChange is not null)
                {
                    <small class="text-muted d-block mt-2">
                        Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </small>
                }
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="card settings-card">
            <div class="card-body">
                <h6 class="fw-semibold mb-3">Active Sessions</h6>
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @if (_security is not null)
                            {
                                @foreach (var session in _security.Sessions)
                                {
                                    var isCurrentSession = session == _security.Sessions.First();
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrentSession)
                                            {
                                                <span class="badge bg-info ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@FormatLastActive(session.LastActive)</td>
                                        <td class="text-end">
                                            @if (!isCurrentSession)
                                            {
                                                <button class="btn btn-sm btn-outline-danger"
                                                        @onclick="() => RequestRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private RenderFragment RenderAppearance() => __builder =>
    {
        <h3 class="settings-section-title">Appearance</h3>

        <div class="card settings-card mb-3">
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <!-- Theme -->
                        <div class="mb-4">
                            <h6 class="fw-semibold">Theme</h6>
                            @foreach (var t in new[] { "Light", "Dark", "System" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme"
                                           id="theme-@t" value="@t" checked="@(_theme == t)"
                                           @onchange="() => _theme = t" />
                                    <label class="form-check-label" for="theme-@t">@t</label>
                                </div>
                            }
                        </div>

                        <!-- Font Size -->
                        <div class="mb-4">
                            <h6 class="fw-semibold">Font Size</h6>
                            @foreach (var s in new[] { "Small", "Medium", "Large" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize"
                                           id="fs-@s" value="@s" checked="@(_fontSize == s)"
                                           @onchange="() => _fontSize = s" />
                                    <label class="form-check-label" for="fs-@s">@s</label>
                                </div>
                            }
                        </div>

                        <!-- Language -->
                        <div class="mb-4">
                            <h6 class="fw-semibold">Language</h6>
                            <select class="form-select" @bind="_language">
                                @foreach (var lang in _availableLanguages)
                                {
                                    <option value="@lang">@lang</option>
                                }
                            </select>
                        </div>

                        <!-- Compact Mode -->
                        <div class="mb-4">
                            <div class="form-check form-switch">
                                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                                <label class="form-check-label" for="compactMode">Compact Mode</label>
                            </div>
                        </div>
                    </div>

                    <div class="col-md-6">
                        <!-- Live Preview -->
                        <h6 class="fw-semibold">Live Preview</h6>
                        <div class="live-preview" style="background:@PreviewBackground; color:@PreviewColor; font-size:@PreviewFontSize; padding:@(_compactMode ? "0.75rem" : "1.25rem"); border-radius:8px; border:1px solid #dee2e6; min-height:200px; transition:all 0.3s ease;">
                            <h6 style="color:@PreviewColor; margin-bottom:@(_compactMode ? "0.25rem" : "0.5rem");">Preview Title</h6>
                            <p style="margin-bottom:@(_compactMode ? "0.25rem" : "1rem");">
                                This is how your content will look with the current settings.
                            </p>
                            <div style="display:flex; gap:@(_compactMode ? "0.25rem" : "0.5rem"); flex-wrap:wrap;">
                                <span class="badge" style="background:@(_theme == "Dark" ? "#89b4fa" : "#0d6efd"); padding:@(_compactMode ? "0.25em 0.5em" : "0.35em 0.65em");">Tag 1</span>
                                <span class="badge" style="background:@(_theme == "Dark" ? "#a6e3a1" : "#198754"); padding:@(_compactMode ? "0.25em 0.5em" : "0.35em 0.65em");">Tag 2</span>
                                <span class="badge" style="background:@(_theme == "Dark" ? "#f9e2af" : "#ffc107"); color:#000; padding:@(_compactMode ? "0.25em 0.5em" : "0.35em 0.65em");">Tag 3</span>
                            </div>
                            <hr style="border-color:@(_theme == "Dark" ? "#45475a" : "#dee2e6");" />
                            <small>Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")</small>
                        </div>
                    </div>
                </div>

                <hr />
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </div>
    };
}
