        border-left-color: transparent;
        border-bottom-color: #0d6efd;
    }

    .sidebar-title {
        text-align: center;
        border-bottom: none;
        padding-bottom: 0.25rem;
    }

    .settings-content {
        padding: 1rem;
    }
}
